local function un(hv,kj)
    assert(type(hv)=="string","Bad argument #1: Expected a string name for the action creator")
    assert(type(kj)=="function","Bad argument #2: Expected a function that creates action objects")
    return setmetatable({name=hv},{
        __call=function(self,...)
            local dx=kj(...)
            assert(type(dx)=="table","Invalid action: An action creator must return a table")
            dx.type=hv
            return dx
        end
    })
end
return un
